var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"핫핫핫, 도와줘서 고맙군.","JPN":"ハハハ、助けてくれてありがとう。","ENG":"Gah hah hah, much appreciated.","TWN":"哈哈哈，多謝你的幫忙。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"물건을 찾고 있었는데 갑자기 침식체가 꼬여서 말이야.","JPN":"物を探していたが、いきなり侵食体にからまれたのだ。","ENG":"I was looking for something and found some C.O.s instead.","TWN":"我正在找東西，結果侵蝕體突然冒出來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"감사인사는 됐어. 당신들이 죽게 뒀으면 어차피 우리한테 꼬였을 테니까.","JPN":"お礼はいい。あなたたちが死んでたらどうせあたしたちに来ていたはずだし。","ENG":"Don't worry about it. They would've come to us if we let you die.","TWN":"不用謝，要是你們死了，我們就會被盯上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"뭐, 그럼- 고마운 건 고마운 거고….","JPN":"まぁ、じゃーありがたいのはさておき……","ENG":"Well, then. I've said my thanks, so...","TWN":"不管怎麼說，還是要謝謝你們…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…가진 게 있다면 넘겨주실까?","JPN":"……持っているものがあるなら、渡してもらおうか？","ENG":"...Hand over what you've got.","TWN":"…不如把你身上的東西交出來吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"특별히 필요한 거라도 있나?","JPN":"特別に必要な物でもあるのか？","ENG":"Is there anything in particular you need?","TWN":"你需要什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신들이 타고 온 배.","JPN":"あなたたちが乗ってきた船。","ENG":"The ship that you brought here.","TWN":"你們乘坐的那艘船。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"인연이군. 이쪽도 너희 배가 필요하거든.","JPN":"奇遇だな、こっちも君たちの船が必要だ。","ENG":"What a coincidence. We need your ship too.","TWN":"這麼巧，我們也需要你們的船。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신들 게 더 컸으면 좋겠네. 난 공정한 배팅은 싫어해서.","JPN":"あなたたちの船の方が大きいことを願うよ。あたしは不公正な取引が好きなんだ。","ENG":"I hope your ship is bigger. I'm not too keen on a fair trade.","TWN":"我希望你的賭注再大一點，我不喜歡公平的賭注。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"핫핫핫! 칼솜씨가 제법 좋군. 어디서 배운 건가?","JPN":"ハハハ！　良い腕だな。どこで習った？","ENG":"Gah hah hah! You're pretty good with that knife. Where did you learn how to use it?","TWN":"哈哈哈！刀法不錯，你從哪裡學的？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"시장에서 생선 손질을 배웠지. 부둣가에서 생선 장사를 했거든.","JPN":"市場で魚をさばきながら習った。港で魚を売っていたんだ。","ENG":"I learned how to handle fish at the market. I used to sell fish at the dockside.","TWN":"我在市場殺魚時學的，我曾經在碼頭賣過魚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"…음? 생선이라고…?","JPN":"……ん？　魚だと……？","ENG":"...Hmm? Fish...?","TWN":"…嗯？賣魚…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"맞혔다!","JPN":"当たった！","ENG":"Got him!","TWN":"打中了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"콜록 콜록.","JPN":"ゲホッゲホッ。","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"야, 나까지 맞을 뻔 했잖아.","JPN":"こら、あたしまで当たるところだったじゃん。","ENG":"Hey, you almost hit me too.","TWN":"喂，你差點打到我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"정말이지- 소냐는 동료에 대한 신뢰가 부족하다니까요.","JPN":"全くー、ソーニャは仲間に対する信頼が足りませんね。","ENG":"Oh, Sonya. You need to have more faith in your crew mates.","TWN":"真是的，索妮雅就是缺乏對夥伴的信任。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으엣? 어째서 제 목덜미에 칼이…?","JPN":"うえ？　何で私の首に刃が……？","ENG":"Eek? Why is there a blade to my throat...?","TWN":"嗯？為什麼有一把刀架在我的脖子上…？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"시도는 좋았어, 아가씨.","JPN":"狙いはよかったな、お嬢さん。","ENG":"That was some valiant effort there, lassie.","TWN":"雕蟲小技，丫頭。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"와앗- 그걸 맞고도 멀쩡하다고요?!","JPN":"うそーあれを当たっても平気なんですか！？","ENG":"Whoa! How are you still standing after that shot?!","TWN":"哇，你被打到卻毫髮無傷？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"이런 것도 못 피했으면 애진작에 바다생활은 접었겠지.","JPN":"こんなものも避けられないなら、海の生活なんかとっくの昔に諦めていた。","ENG":"I should've quit the seafaring life if I couldn't avoid things like that.","TWN":"這種東西我都閃不過的話，應該要早早放棄海上生活吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"큿! 저를 어쩔 생각이죠? 묶어서 널빤지에 매달고 고래밥으로 줄 건가요?!","JPN":"くっ！　私をどうするつもりですか？　板に締めてクジラのエサにでもするつもりですか！？","ENG":"Kgh! What are you going to do to me?! Are you going to make me walk the plank?!","TWN":"唔！你想做什麼？你要把我綁在木板上餵鯨魚嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"뭐, 이야기 속 해적의 방식대로라면 그것도 나쁘진 않겠지.","JPN":"まぁ、物語の中の海賊のやり方に従うのなら、それも悪くはない。","ENG":"Well, that's not a bad idea if we were to follow the ways of pirates in children's tales.","TWN":"照著故事裡海盜的處理方式去做好像也不錯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"살려주세요! 살려만 주시면 저희 선장님을 넘겨드릴게요!","JPN":"助けてください！　助けてくれたら私たちの船長をお渡しします！","ENG":"Please, spare me! Let me go and I'll give you our captain instead!","TWN":"大人饒命！只要你放過我，我就把船長交給你！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"너 아까 나한테 신뢰 어쩌고 하지 않았어?","JPN":"あなたさっきあたしに信頼がどうとか言わなかったか？","ENG":"Weren't you saying something about faith in crew mates and whatnot?","TWN":"你剛剛還說我不信任你？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그치만 동료보단 제 목숨이 더 소중한 걸요!","JPN":"でも、仲間より自分の命が大事なんです！","ENG":"But I value my own life over my crew mates!","TWN":"比起夥伴，我更珍惜自己的生命！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"핫핫핫, 한결 같아서 마음에 드는 아가씨군.","JPN":"ハハハ、裏表がなくて気に入った、お嬢さん。","ENG":"Gah hah hah, this here lassie is consistent, I'll give you that.","TWN":"哈哈哈，小丫頭，你真合我胃口。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"됐어. 일전에도 신세를 진 게 있으니 넘어가자고.","JPN":"いい。前も世話になったことがあるから、ちゃらってことで。","ENG":"Yer free to go, lass. Let's call it even since I owe you one.","TWN":"你們走吧，就當作是還你們一個人情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이… 일전에도? 그게 무슨 소리죠?","JPN":"ま……前？　それってどういうことです？","ENG":"Y-you owe us one...? What do you mean?","TWN":"還…人情？這是什麼意思？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"너희 해적단이 그날 격벽에서 소란을 일으켜준 덕에, 나도 조용히 탈출할 수 있었거든.","JPN":"あの時、君達海賊団が隔壁で騒ぎを起こしてくれたおかげで私もこっそり脱出できたんだ。","ENG":"Thanks to you pirates causing a ruckus at the ocean wall that day, I was able to quietly escape too.","TWN":"那天多虧你們海盜團在隔離牆那大鬧，我才得以悄悄逃走。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 웃음소리 덕에 기억 났어.","JPN":"その笑い声で思い出した。","ENG":"I remember your laughter.","TWN":"聽到你的笑聲我想起來了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"반장 옆에서 일하던 아저씨, 맞지?","JPN":"班長の隣で働いていたおじさん、だよな？","ENG":"You were the guy who was working next to the supervisor, right?","TWN":"你是之前跟在班長旁邊的大叔對吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NONAME","text":{"KOREA":"난 해적 잭이다. 그리고 보물사냥꾼이지.","JPN":"私は海賊、ジャックだ。そしてトレジャーハンターでもある。","ENG":"Name's Jack. I'm a pirate, as well as a treasure hunter.","TWN":"我是海盜傑克，也是個寶藏獵人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};